var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"크윽?!","JPN":"くうっ……","ENG":"Hngh!","TWN":"呃？！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장!!","JPN":"隊長！！","ENG":"Captain!","TWN":"隊長！！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 괜찮아? 일어설 수 있겠어?","JPN":"隊長、大丈夫か？　立てる？","ENG":"Are you alright? Can you get up?","TWN":"隊長，沒事吧？能站起來嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"제기랄...... 자동차에 들이받은 기분이군......","JPN":"くそっ……車に引かれた気分だな……","ENG":"Geez... It feels like a truck ran into me...","TWN":"可惡……這感覺就像撞上了汽車一樣……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"몇 군데나 부러졌는지 감도 안 잡히는데......","JPN":"何箇所折れたか見当もつかない……","ENG":"I can't even tell how many bones I broke just now...","TWN":"好幾處的骨頭都斷掉了……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"쥐새끼들인 줄 알았는데 고약한 바퀴벌레들이었군.","JPN":"ドブネズミかと思ったが、しつこいゴキブリだったようだな。","ENG":"I thought you were a bunch of rats, but it turns out you're nasty roaches.","TWN":"本以為是一群老鼠，沒想到原來是可惡的蟑螂。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"보통 이 정도로 당하고도 살겠다고 발악하는 것들은 잘 없는데 말이야.","JPN":"これぐらいやられても生きようともがく人間なんて、ほとんどいないんだが。","ENG":"Usually folks aren't this tenacious about survival when they've taken a beating like that.","TWN":"我很少見到遭到如此重創還會拼命掙扎的人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......이 정도로 눈치를 줬으면 뭔가 보여줘야겠다는 생각이 들지 않나?","JPN":"……そろそろ何か見せてくれる気にはならないか？","ENG":"... Haven't I shown you enough... what to do now?","TWN":"我暗示了這麼久，你不覺得該表現點什麼嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"분명 엄청난 명사수라고 부하들에게 소개받았는데 말이지.","JPN":"凄腕のスナイパーと部下から紹介されたはずなんだがな。","ENG":"My boys said you were quite the shot when they brought you.","TWN":"我聽手下們說你是了不起的神射手。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"아까부터 총을 쏘는 모습이 영 마음에 들지 않는걸.","JPN":"さっきから銃を撃つ様子が気に入らないな。","ENG":"But your shooting hasn't been that impressive just yet.","TWN":"但我對你剛才的射擊術不是很滿意。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"무슨 말을 하고 싶은 거야?","JPN":"何が言いたい？","ENG":"What are you trying to say?","TWN":"你想說什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"자네를 고용한 걸 후회하지 않도록 슬슬 성과를 보여 주면 좋겠어.","JPN":"お前を雇ったことを後悔しないように、そろそろ成果を見せてほしい。","ENG":"I'm saying don't make me regret hiring you.","TWN":"為了不讓我反悔雇傭你，你最好儘快展現你真正的實力。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"더 자세한 설명이 필요한가?","JPN":"もっと詳しい説明が必要か？","ENG":"Need I say more?","TWN":"還需要我更仔細地說明嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......알겠어.","JPN":"……わかった。","ENG":"Understood.","TWN":"……知道了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내가 끝을 내지.","JPN":"俺が終わらせてやる。","ENG":"I'll put an end to this.","TWN":"我來了結他們。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그래, 그거야. 어차피 돌아섰는데 미련을 남겨봐야 뭐 하겠어.","JPN":"そう、そうこなくてはな。どうせ裏切ったんだ、未練なんか残しても仕方ない。","ENG":"That's the spirit. There's no going back anymore.","TWN":"就是這樣。反正已經分道揚鑣了，還有什麼好留戀的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"병상에 누워 있는 동생을 생각해 보라고.","JPN":"病床に伏せている妹を考えろ。","ENG":"Think about your poor little sister in her hospital bed.","TWN":"想想你躺在病床上的弟弟吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"최지훈...... 너 정말 우리를......","JPN":"ゴトウ……本当に私たちを……","ENG":"Jihoon... You really...","TWN":"崔智勳……你是真心……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이유리.","JPN":"カスカベ・ユリ。","ENG":"Lee Yuri.","TWN":"李悠麗。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"난 민병대도 싫고 대장도 엿 같았지만...... 사실 네가 제일 싫었어.","JPN":"俺は民兵隊も隊長も嫌いだったが……お前のことが一番嫌いだった。","ENG":"I hated the Militia and the Captain... but I hated you the most.","TWN":"我討厭民兵隊，也討厭隊長……但最討厭的人是妳。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐야?!","JPN":"何だと！？","ENG":"What?","TWN":"什麼？！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"왜냐하면...... 넌 정말 예전의 나를 보는 것 같았거든.","JPN":"……お前を見ていると、昔の自分を見ている気がしたからな。","ENG":"Because... you reminded me of my younger self.","TWN":"因為……妳和從前的我像極了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"민병대라는 곳은 차라리 빨리 죽는 게 살아남는 것 보다 나을 때가 있어.","JPN":"民兵隊にいると、生き残るよりもいっそ早く死んだ方がマシだと思うことが多い。","ENG":"Sometimes it's better to die first than survive when you're in the Militia.","TWN":"在民兵隊，很多時候生不如死。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래서? 날 죽여줄 테니까 감사라도 하라는 거야?","JPN":"それで？　殺してやるから感謝しろって？","ENG":"So what? Are you saying I should be grateful because you'll whack me?","TWN":"所以呢？我得感謝你殺我之恩？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不是。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"혹시라도 안 죽고 너무 오래 살아남으면......","JPN":"もし死ぬことができずに、長生きでもしちまったら……","ENG":"I'm just saying if you happen to survive long enough...","TWN":"如果妳不小心活了太久……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"나처럼 추해지기 전에 미리미리 은퇴할 자리를 찾아두라고.","JPN":"俺みたいに墜ちるところまで墜ちる前に、さっさと引退しろってことだ。","ENG":"Find a better retirement option before you hit rock bottom like me.","TWN":"就好好準備退役，別像我一樣落到這種地步。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 그게 무슨 뜻이야?","JPN":"は？　どういう意味だ？","ENG":"Huh? What do you mean?","TWN":"什麼？什麼意思？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"최지훈?!","JPN":"ゴトウ！？","ENG":"Choi Jihoon?","TWN":"崔智勳？！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"뭐야, 너? 몸에 두른 그건 뭐지?","JPN":"なんだそれは？　いったい何を巻いている……？","ENG":"Hey! What are those around your body?","TWN":"你那是？你身上披著什麼東西？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"보면 몰라? 폭탄이잖아.","JPN":"見りゃわかるだろ？　爆弾さ。","ENG":"Can't you tell? They're bombs.","TWN":"看不清楚嗎？是炸彈。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"무기상 영감이 네게 전해주라고 한 이별 선물이다.","JPN":"武器屋のジジイがお前に届けろって渡してくれた、お別れのプレゼントだ。","ENG":"A little farewell gift from the old gunsmith.","TWN":"這是武器商老頭送給你的臨別禮物。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"우릴 뜨끈한 불지옥으로 데려가 줄 급행 티켓이지!","JPN":"俺らを熱い炎の地獄まで運んでくれる特急列車の切符さ！","ENG":"A one-way ticket to hell for the both of us!","TWN":"它會把我們引導至無間煉獄！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"이런 개자식이?! 동생이 어떻게 되어도 상관 없나 보지?","JPN":"てめえ……！　妹がどうなっても構わないのか？","ENG":"You crazy moron! Don't you even care about your sister?","TWN":"你這狗東西？！你不管你弟弟的死活嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아, 그리고 내 동생 말인데......","JPN":"ああ、俺の妹のことだが……","ENG":"Oh, speaking of my sister...","TWN":"對了，我的弟弟……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"벌써 옛날에 죽었어. 성냥이나 팔아대는 어떤 미친놈의 인질극에 휘말려서 말이야.","JPN":"とっくの昔に死んでるんだ。マッチを売る、あるキチガイの人質事件に巻き込まれてな。","ENG":"She already died a long time ago. Some maniac who sold matches used her as hostage.","TWN":"其實他早就死了，被捲入了一個賣火柴的瘋子的人質鬧劇。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"알겠냐, 머저리 씨.","JPN":"わかったか、クソ野郎。","ENG":"Catch my drift, you idiot?","TWN":"明白了嗎，笨蛋。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"최지훈! 무슨 짓을 하려는 거야? 안 돼!","JPN":"ゴトウ！　何の真似だ！　やめろ！","ENG":"Jihoon! What are you doing? No!","TWN":"崔智勳！你想幹什麼？不要！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리! 엎드려!!","JPN":"カスカベ！　伏せろ！！","ENG":"Yuri! Get down!","TWN":"李悠麗！趴下！！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};